To prevent Cross-Site Scripting (XSS) attacks, you can sanitize the user input before displaying it in the response. Here's an updated version of the code that includes input sanitization using ESAPI (OWASP Enterprise Security API) to encode special characters and prevent XSS attacks:

```java
import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedUserInput = sanitizeInput(userInput);
        String output = "Hello, " + sanitizedUserInput + "!";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("<h1>" + output + "</h1>");
        out.println("</body></html>");
    }

    private String sanitizeInput(String input) {
        try {
            return ESAPI.encoder().encodeForHTML(input);
        } catch (EncodingException e) {
            // Handle encoding exception
            e.printStackTrace();
            return "";
        }
    }
}
